import { NavLink } from 'react-router-dom';
const Card = ({ title, image }) => {
    return (
        <>
            <div>
                <div className="grid">
                    <div className="apartment">
                        <NavLink to="/flat">
                            <div className="apartment__subtitle">
                                {title}
                            </div>
                        </NavLink>
                    </div>
                </div>
            </div>
        </>
    );
};

export default Card;
